import type { FC } from 'react';
import React from 'react';

import { Slide } from './Slide';
import type { SlidesProps } from './Slides.types';
import { Stepper } from './Stepper';

export const Slides: FC<SlidesProps> = ({ content, activeSlideIndex = 0, onPaginationChange }) => (
	<>
		<Slide {...content[activeSlideIndex]} />
		{content.length && (
			<Stepper content={content} activeSlideIndex={activeSlideIndex} onPaginationChange={onPaginationChange} />
		)}
	</>
);
